class Solution:
    def isRationalEqual(self, s: str, t: str) -> bool:
        return self.convert(s) == self.convert(t)

    def convert(self, s: str) -> float:
        i = 0
        integer_part = 0
        while i < len(s) and s[i] != '.' and s[i] != '(':
            integer_part = integer_part * 10 + int(s[i])
            i += 1

        if i < len(s) and s[i] == '.':
            i += 1
            non_repeating_part = 0
            non_repeating_len = 0
            while i < len(s) and s[i] != '(':
                non_repeating_part = non_repeating_part * 10 + int(s[i])
                non_repeating_len += 1
                i += 1

            if i < len(s) and s[i] == '(':
                i += 1
                repeating_part = 0
                repeating_len = 0
                while i < len(s) and s[i] != ')':
                    repeating_part = repeating_part * 10 + int(s[i])
                    repeating_len += 1
                    i += 1
                i += 1  # skip ')'
                return integer_part + (non_repeating_part / (10 ** non_repeating_len)) + (repeating_part / ((10 ** repeating_len) - 1)) / (10 ** non_repeating_len)
            else:
                return integer_part + (non_repeating_part / (10 ** non_repeating_len))
        else:
            return integer_part
